/**
 * Represents the result of an HTTP request.
 */
data class HttpResult(
    val statusCode: Int,
    val body: String?,
    val headers: Map<String, String>,
    val isSuccessful: Boolean,
    val error: Exception?
) {
    /**
     * Parses the response body as a JSONObject.
     */
    fun bodyAsJson(): JSONObject? {
        return try {
            body?.let { JSONObject(it) }
        } catch (e: Exception) {
            null
        }
    }
}

/**
 * Callback interface for asynchronous HTTP requests.
 */
fun interface HttpCallback {
    fun onResult(result: HttpResult)
}

// ========================
// Usage Example
// ========================

object IoTClientExample {
    fun example() {
        val client = IoTHttpClient.create(
            connectTimeoutSeconds = 5,
            readTimeoutSeconds = 15,
            writeTimeoutSeconds = 15
        )

        // --- Cloud API usage (HTTPS, secure client) ---

        // Synchronous cloud GET
        Thread {
            val devicesResult = client.cloudGet("/v1/devices", authToken = "my-auth-token")
            if (devicesResult.isSuccessful) {
                val json = devicesResult.bodyAsJson()
                Log.d("Example", "Devices: $json")
            } else {
                Log.e("Example", "Cloud GET failed: ${devicesResult.statusCode} ${devicesResult.error?.message}")
            }
        }.start()

        // Synchronous cloud POST
        Thread {
            val registerBody = JSONObject().apply {
                put("deviceId", "sensor-001")
                put("type", "temperature")
            }
            val registerResult = client.cloudPost("/v1/devices/register", registerBody, authToken = "my-auth-token")
            Log.d("Example", "Register result: ${registerResult.statusCode}")
        }.start()

        // --- Local IoT device usage (HTTP, insecure client) ---

        // Synchronous local device status
        Thread {
            val statusResult = client.getDeviceStatus("192.168.1.100", port = 80, endpoint = "/status")
            if (statusResult.isSuccessful) {
                Log.d("Example", "Device status: ${statusResult.body}")
            }
        }.start()

        // Synchronous local device command
        Thread {
            val command = JSONObject().apply {
                put("action", "toggle")
                put("target", "relay_1")
            }
            val commandResult = client.sendDeviceCommand(
                deviceIp = "192.168.1.100",
                port = 80,
                endpoint = "/api/command",
                command = command
            )
            Log.d("Example", "Command result: ${commandResult.statusCode} - ${commandResult.body}")
        }.start()

        // Asynchronous device discovery
        client.discoverDevice("192.168.1.101", port = 80, endpoint = "/info") { result ->
            if (result.isSuccessful) {
                Log.d("Example", "Device discovered: ${result.body}")
            } else {
                Log.d("Example", "Device not found at 192.168.1.101")
            }
        }

        // Asynchronous local device command
        val asyncCommand = JSONObject().apply {
            put("brightness", 75)
        }
        client.sendDeviceCommandAsync(
            deviceIp = "192.168.1.102",
            port = 80,
            endpoint = "/api/light",
            command = asyncCommand
        ) { result ->
            Log.d("Example", "Async command result: ${result.statusCode}")
        }

        // Async cloud GET
        client.getAsync(
            "https://api.example.com/v1/health",
            headers = mapOf("Authorization" to "Bearer my-auth-token")
        ) { result ->
            Log.d("Example", "Cloud health: ${result.isSuccessful}")
        }

        // Direct HTTP/HTTPS usage with arbitrary URLs
        Thread {
            // HTTP to local device
            val httpResult = client.get("http://192.168.1.200/api/sensors")
            Log.d("Example", "HTTP sensor data: ${httpResult.body}")

            // HTTPS to external service
            val httpsResult = client.get("https://api.example.com/v1/firmware/latest")
            Log.d("Example", "HTTPS firmware info: ${httpsResult.body}")
        }.start()

        // Don't forget to shutdown when done
        // client.shutdown()
    }
}